        assertEquals(3.5, data5.quantile(0.25, QuantileMethod.HAZEN), tol)
        assertEquals(4.0, data5.quantile(0.3, QuantileMethod.HAZEN), tol)
        assertEquals(6.0, data5.quantile(0.5, QuantileMethod.HAZEN), tol)
        assertEquals(8.5, data5.quantile(0.75, QuantileMethod.HAZEN), tol)
        assertEquals(10.0, data5.quantile(0.9, QuantileMethod.HAZEN), tol)
        assertEquals(10.0, data5.quantile(1.0, QuantileMethod.HAZEN), tol)
    }

    @Test
    fun testQuantileWeibullKnownValues() {
        // HF6: h = (n+1)*q, linear interpolation
        // numpy: np.quantile([2,4,6,8,10], q, method='weibull')
        assertEquals(2.0, data5.quantile(0.0, QuantileMethod.WEIBULL), tol)
        assertEquals(2.0, data5.quantile(0.1, QuantileMethod.WEIBULL), tol)
        assertEquals(3.0, data5.quantile(0.25, QuantileMethod.WEIBULL), tol)
        assertEquals(3.6, data5.quantile(0.3, QuantileMethod.WEIBULL), tol)
        assertEquals(6.0, data5.quantile(0.5, QuantileMethod.WEIBULL), tol)
        assertEquals(9.0, data5.quantile(0.75, QuantileMethod.WEIBULL), tol)
        assertEquals(10.0, data5.quantile(0.9, QuantileMethod.WEIBULL), tol)
