    @Test
    fun testQuantileLinearKnownValues() {
        // HF7: h = (n-1)*q + 1, linear interpolation
        // numpy: np.quantile([2,4,6,8,10], q, method='linear')
        assertEquals(2.0, data5.quantile(0.0, QuantileMethod.LINEAR), tol)
        assertEquals(2.8, data5.quantile(0.1, QuantileMethod.LINEAR), tol)
        assertEquals(4.0, data5.quantile(0.25, QuantileMethod.LINEAR), tol)
