    }

    @Test
    fun testQuantileMedianUnbiasedKnownValues() {
        // HF8: h = (n + 1/3)*q + 1/3, linear interpolation
        // numpy: np.quantile([2,4,6,8,10], q, method='median_unbiased')
        assertEquals(2.0, data5.quantile(0.0, QuantileMethod.MEDIAN_UNBIASED), tol)
        assertEquals(2.0, data5.quantile(0.1, QuantileMethod.MEDIAN_UNBIASED), tol)
        assertEquals(3.33333333333333, data5.quantile(0.25, QuantileMethod.MEDIAN_UNBIASED), tol)
        assertEquals(3.86666666666667, data5.quantile(0.3, QuantileMethod.MEDIAN_UNBIASED), tol)
        assertEquals(6.0, data5.quantile(0.5, QuantileMethod.MEDIAN_UNBIASED), tol)
        assertEquals(8.66666666666667, data5.quantile(0.75, QuantileMethod.MEDIAN_UNBIASED), tol)
        assertEquals(10.0, data5.quantile(0.9, QuantileMethod.MEDIAN_UNBIASED), tol)
        assertEquals(10.0, data5.quantile(1.0, QuantileMethod.MEDIAN_UNBIASED), tol)
    }

    @Test
    fun testQuantileNormalUnbiasedKnownValues() {
        // HF9: h = (n + 1/4)*q + 3/8, linear interpolation
        // numpy: np.quantile([2,4,6,8,10], q, method='normal_unbiased')
        assertEquals(2.0, data5.quantile(0.0, QuantileMethod.NORMAL_UNBIASED), tol)
        assertEquals(2.0, data5.quantile(0.1, QuantileMethod.NORMAL_UNBIASED), tol)
