    @Test
    fun testQuantileSelectClosestObservationKnownValues() {
        val data = listOf(10, 30, 50, 70, 90)
        // HF3 with banker's rounding (ties to even): h=n*q
        assertEquals(10, data.quantileSelect(0.0, QuantileMethod.CLOSEST_OBSERVATION))
        assertEquals(10, data.quantileSelect(0.1, QuantileMethod.CLOSEST_OBSERVATION))
        // h=1.25, round=1 -> data[0]=10
        assertEquals(10, data.quantileSelect(0.25, QuantileMethod.CLOSEST_OBSERVATION))
        // h=2.5, bankersRound(2.5)=2 (even) -> data[1]=30
        assertEquals(30, data.quantileSelect(0.5, QuantileMethod.CLOSEST_OBSERVATION))
        // h=3.75, round=4 -> data[3]=70
        assertEquals(70, data.quantileSelect(0.75, QuantileMethod.CLOSEST_OBSERVATION))
        assertEquals(90, data.quantileSelect(1.0, QuantileMethod.CLOSEST_OBSERVATION))
    }

