    // ── Edge: two elements ─────────────────────────────────────────────────────

    @Test
    fun testQuantileTwoElementsLinear() {
        val data = doubleArrayOf(3.0, 7.0)
        // h = (n-1)*q + 1 = q + 1
        assertEquals(3.0, data.quantile(0.0, QuantileMethod.LINEAR), tol)
        assertEquals(4.0, data.quantile(0.25, QuantileMethod.LINEAR), tol)
        assertEquals(5.0, data.quantile(0.5, QuantileMethod.LINEAR), tol)
        assertEquals(6.0, data.quantile(0.75, QuantileMethod.LINEAR), tol)
        assertEquals(7.0, data.quantile(1.0, QuantileMethod.LINEAR), tol)
    }

    @Test
    fun testQuantileTwoElementsDiscrete() {
        val data = doubleArrayOf(3.0, 7.0)
        // LOWER: h = (n-1)*q + 1. For q=0.5: h=1.5, floor=1, idx=0 -> 3.0
        assertEquals(3.0, data.quantile(0.5, QuantileMethod.LOWER), tol)
        // HIGHER: ceil(1.5)=2, idx=1 -> 7.0
        assertEquals(7.0, data.quantile(0.5, QuantileMethod.HIGHER), tol)
        // NEAREST: floor(1.5+0.5)=floor(2.0)=2, idx=1 -> 7.0 (rounds half up)
        assertEquals(7.0, data.quantile(0.5, QuantileMethod.NEAREST), tol)
        // MIDPOINT: (3+7)/2 = 5.0
        assertEquals(5.0, data.quantile(0.5, QuantileMethod.MIDPOINT), tol)
    }

    @Test
    fun testQuantileTwoElementsHFMethods() {
        val data = doubleArrayOf(3.0, 7.0)
        // kstats implementation values for q=0.5 on [3, 7]
        assertEquals(3.0, data.quantile(0.5, QuantileMethod.INVERTED_CDF), tol)
        // HF2: h=1.5, h-0.5=1.0, ceil(1.0)=1, idx=0, isDisc=(1.0==floor(1.0))=true -> average
        assertEquals(5.0, data.quantile(0.5, QuantileMethod.AVERAGED_INVERTED_CDF), tol)
        // HF3: h=1.0, bankersRound(1.0)=1, idx=0 -> 3.0
        assertEquals(3.0, data.quantile(0.5, QuantileMethod.CLOSEST_OBSERVATION), tol)
        // HF4: h=1.0, clamped=1.0, j=1, g=0 -> x[0]=3.0
        assertEquals(3.0, data.quantile(0.5, QuantileMethod.INTERPOLATED_INVERTED_CDF), tol)
        // HF5: h=1.5, interpolation between x[0]=3 and x[1]=7: 3+0.5*4=5.0
        assertEquals(5.0, data.quantile(0.5, QuantileMethod.HAZEN), tol)
        // HF6: h=(3)*0.5=1.5, interpolation: 5.0
        assertEquals(5.0, data.quantile(0.5, QuantileMethod.WEIBULL), tol)
        // HF8, HF9: interpolation, result=5.0
        assertEquals(5.0, data.quantile(0.5, QuantileMethod.MEDIAN_UNBIASED), tol)
        assertEquals(5.0, data.quantile(0.5, QuantileMethod.NORMAL_UNBIASED), tol)
    }

